# Unity Catalog — Flow A (plain reference load) + Flow B (medallion bronze/silver/gold).
# The workspace PAT's principal (workspace admin, §0) owns these; grants go to that user.

data "databricks_current_user" "me" {}

resource "databricks_catalog" "dataq" {
  name    = var.uc_catalog
  comment = "DataQ harness retail catalog (Flow A reference load + Flow B medallion)."

  properties = {
    purpose = "dataq-harness"
  }
}

resource "databricks_schema" "schemas" {
  for_each     = toset(var.uc_schemas)
  catalog_name = databricks_catalog.dataq.name
  name         = each.value
  comment      = "DataQ harness ${each.value} layer."
}

# Catalog-level grants for the DataQ principal (the PAT user).
resource "databricks_grants" "catalog" {
  catalog = databricks_catalog.dataq.name
  grant {
    principal  = data.databricks_current_user.me.user_name
    privileges = ["USE_CATALOG", "USE_SCHEMA", "SELECT"]
  }
}

